import java.util.*;

class Codechef {
    public static void main(String[] args) throws java.lang.Exception {
        Scanner scanner = new Scanner(System.in);

        // Read the number of customers (n) and the number of rice bags (m)
        int n = scanner.nextInt(); // number of customers
        int m = scanner.nextInt(); // number of rice bags

        List<int[]> customers = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            int a = scanner.nextInt(); // customer's quantity preference
            int b = scanner.nextInt(); // customer's cost preference
            customers.add(new int[]{b, a}); // storing as {cost, quantity}
        }

        List<int[]> riceBags = new ArrayList<>();
        for (int i = 0; i < m; i++) {
            int q = scanner.nextInt(); // bag quantity
            int p = scanner.nextInt(); // bag cost
            riceBags.add(new int[]{p, q}); // storing as {cost, quantity}
        }

        // Sort customers and rice bags by cost
        customers.sort(Comparator.comparingInt(a -> a[0]));
        riceBags.sort(Comparator.comparingInt(a -> a[0]));

        int[] good = new int[m]; // array to track which rice bags have been used
        int ans = 0; // answer to store the total number of satisfied customers

        for (int i = 0; i < n; i++) {
            int quan = -1;
            int index = -1;
            for (int j = 0; j < m; j++) {
                if (good[j] == 0) { // check if rice bag has not been used
                    if (riceBags.get(j)[0] > customers.get(i)[0]) break; // rice cost must be <= customer's cost
                    if (riceBags.get(j)[1] > customers.get(i)[1]) { // rice quantity must be > customer's quantity
                        if (quan == -1) {
                            quan = riceBags.get(j)[1];
                            index = j;
                        } else {
                            if (quan > riceBags.get(j)[1]) {
                                index = j;
                                quan = riceBags.get(j)[1];
                            }
                        }
                    }
                }
            }
            if (index != -1) { // if a suitable rice bag is found
                good[index] = 1; // mark it as used
                ans++; // increment satisfied customers count
            }
        }

        System.out.println(ans); // print the total number of satisfied customers
        scanner.close();
    }
}

